import {
  CCol,
  CForm,
  CFormInput,
  CFormTextarea,
  CFormSelect,
  CButton,
} from "@coreui/react";
import React, { useState } from "react";
import GetTestimonialDetails from "src/components/services/GetTestimonialDetails";

const addTestimonial = () => {
  const [formData, setFormData] = useState({
    name: "",
    company: "",
    content: "",
    rating: "",
  });

  const handleChange = (event) => {
    setFormData({
      ...formData,
      [event.target.name]: event.target.value,
    });
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    let data = {
      name: formData.name,
      company: formData.company,
      content: formData.content,
      rating: formData.rating,
    };
    let testimonial = await GetTestimonialDetails.addTestimonial(data);
    if (testimonial) {
      window.location.href = "http://localhost:3000/testimonial/list";
    }
  };

  return (
    <div>
      <CForm className="row g-3">
        <CCol md={6}>
          <CFormInput
            type="text"
            id="name"
            label="Name"
            name="name"
            value={formData.name}
            onChange={handleChange}
          />
        </CCol>
        <CCol md={6}>
          <CFormInput
            type="text"
            id="company"
            label="Company Name"
            name="company"
            value={formData.company}
            onChange={handleChange}
          />
        </CCol>
        <CCol md={6}>
          <CFormSelect
            value={formData.rating}
            aria-label="rating"
            name="rating"
            options={[
              "Select Rating",
              { label: "One", value: "1" },
              { label: "Two", value: "2" },
              { label: "Three", value: "3" },
              { label: "Four", value: "4" },
              { label: "Five", value: "5" },
            ]}
            onChange={handleChange}
          />
        </CCol>
        <CCol md={6}>
          <CFormTextarea
            value={formData.content}
            id="content"
            label="Content"
            rows={3}
            name="content"
            text="Must be 80 words long."
            onChange={handleChange}
          ></CFormTextarea>
        </CCol>
        <CCol md={3}>
          <CButton type="submit" color="primary" onClick={handleSubmit}>
            Create
          </CButton>
        </CCol>
      </CForm>
    </div>
  );
};

export default addTestimonial;
